-- ── LESSONS: Vibecoding Fundamentals ─────────────────────────────────────────

INSERT OR IGNORE INTO lessons (id, course_id, title, description, content, position, duration_minutes, quiz) VALUES
(
  'les-vc-001', 'crs-vibe-001',
  'What is Vibecoding?',
  'The paradigm shift: from writing every line to directing AI toward your vision.',
  'Vibecoding is a programming paradigm where you describe what you want to build in plain language and AI translates your intent into working code. The term was coined by Andrej Karpathy in 2025 to describe the experience of building software by directing an AI model rather than writing every line manually. Instead of fighting syntax and boilerplate, you focus on product design, user experience, and the logic that actually matters.

The core loop is simple: describe what you need, let AI generate the code, review it carefully, refine based on what you observe, and ship. This does not replace programming knowledge — the best vibecoders understand code well enough to evaluate AI output, catch bugs before they ship, and structure prompts so the AI has the full context it needs. Think of it as pair programming where the AI writes the first draft and you are the senior engineer steering the direction.

In this course you will build real applications from scratch using vibecoding techniques. Each lesson combines a concept with a hands-on task. By the end you will have shipped at least one complete full-stack project using AI as your co-pilot.',
  1, 8,
  '{"questions":[{"q":"Who coined the term Vibecoding?","options":["Sam Altman","Andrej Karpathy","Linus Torvalds","Jeff Dean"],"answer":1},{"q":"What is the core vibecoding loop?","options":["design-code-test-deploy","describe-generate-review-ship","plan-build-monitor-iterate","sketch-prototype-test-launch"],"answer":1},{"q":"Vibecoding is best described as:","options":["Replacing programmers with AI","Letting AI write code without any review","Pair programming with AI where you steer and review the output","Automating the entire software development lifecycle"],"answer":2},{"q":"The most important skill a vibecoder needs is:","options":["Memorising syntax","Speed-typing","Understanding code well enough to evaluate and steer AI output","Knowing every framework"],"answer":2}]}'
),
(
  'les-vc-002', 'crs-vibe-001',
  'Setting Up Your AI-Powered IDE',
  'Configure Cursor IDE and your .cursorrules file for maximum vibecoding velocity.',
  'Cursor is the leading vibecoding IDE, built on top of VS Code with AI capabilities integrated directly into the editing experience. Tab completion understands your entire codebase context, inline chat handles quick targeted edits, and Composer mode (open with Cmd+I on Mac or Ctrl+I on Windows) handles larger multi-file changes. On the free tier you get 500 fast requests per month — enough to build real projects while learning.

The single most impactful configuration step is creating a .cursorrules file at the root of your project. This file tells the AI about your technology stack, your coding conventions, and any patterns it should follow or avoid. A well-written .cursorrules file dramatically improves suggestion quality because the model understands your project from the start rather than guessing. Include: your framework and language versions, your preferred component patterns, any custom utility functions it should reuse, and style guidelines you want enforced.',
  2, 10,
  '{"questions":[{"q":"What is Cursor IDE built on top of?","options":["Vim","Neovim","VS Code","Emacs"],"answer":2},{"q":"Which Cursor mode is best for multi-file changes?","options":["Tab completion","Inline rename","Composer mode","Find and replace"],"answer":2},{"q":"What does the .cursorrules file configure?","options":["Linting rules","Keyboard shortcuts","AI conventions about your stack and coding style","Deployment settings"],"answer":2},{"q":"How do you open Composer mode in Cursor?","options":["Cmd+P / Ctrl+P","Cmd+K / Ctrl+K","Cmd+I / Ctrl+I","Cmd+Shift+P / Ctrl+Shift+P"],"answer":2}]}'
),
(
  'les-vc-003', 'crs-vibe-001',
  'Your First App in 10 Minutes',
  'Build a complete working application in one session using the describe-generate-refine loop.',
  'The best way to learn vibecoding is to build something real immediately. Open Cursor Composer and describe a complete application — not individual functions or files, but the full product. For example: "Build a React todo app with TypeScript and Tailwind. Tasks have a title, done status, and created date. Support adding, completing, and deleting tasks. Store tasks in localStorage. Make it look clean with a dark background." Notice what this prompt includes: the tech stack, the data shape, all the features, and the visual direction. Specific prompts produce usable code.

After the AI generates the initial version, run it and note what works and what does not. Then do a second iteration describing only the specific problems: "The delete button is too small on mobile — make it a full-width button below the task text on small screens." Each iteration refines the product. The goal of your first session is not perfection — it is shipping something that works. Get to a working state in 10 minutes, then iterate. Momentum is more valuable than perfection when you are learning.',
  3, 10,
  '{"questions":[{"q":"When writing your first vibecoding prompt, you should describe:","options":["Individual functions to write","Line-by-line instructions","The full product with stack, features, and visual direction","Only the database schema"],"answer":2},{"q":"What is the goal of your first vibecoding session?","options":["Perfect production-ready code","Understanding every line generated","Shipping something that works within 10 minutes","Writing comprehensive tests"],"answer":2},{"q":"In a second-iteration prompt, you should focus on:","options":["Rewriting the entire codebase","Specific problems or improvements observed in the running app","Adding random new features","Changing the tech stack"],"answer":1},{"q":"Vague prompts produce:","options":["Better code because the AI has more freedom","Vague code","Error messages","Faster results"],"answer":1}]}'
),
(
  'les-vc-004', 'crs-vibe-001',
  'Prompt Engineering for Code',
  'Structure your prompts for maximum output quality — context, task, and constraints.',
  'Effective prompt engineering for code differs from prompting for text. You are specifying a software system, not writing an essay. The key is to think like an architect: describe the WHAT and WHY clearly and let the AI handle the HOW. Structure every prompt with three layers: context (what project and stack you are working in), the task (what specifically needs to change or be built), and constraints (things that must or must not happen). For example: "In this TanStack Start project with a Cloudflare D1 database, add a server function that returns quiz results for the current user. Use the existing pattern from getModuleDetail in data.ts. Do not modify the database schema."

Use examples when the task involves an unfamiliar pattern. Show the AI an existing function that follows the pattern you want and say "following this same pattern, build..." Concrete examples reduce the gap between what you mean and what the AI generates. Learn to iterate quickly rather than trying to write the perfect prompt upfront — give direction, evaluate the output, redirect. The fastest vibecoders have tight feedback loops, not perfect prompts.',
  4, 12,
  '{"questions":[{"q":"The three layers of a well-structured code prompt are:","options":["Title, body, conclusion","Context, task, constraints","Frontend, backend, database","Input, processing, output"],"answer":1},{"q":"When describing a coding task, you should focus on:","options":["The HOW — exact implementation details","Variable names and function signatures","The WHAT and WHY — the intent and requirements","The specific lines to change"],"answer":2},{"q":"The most effective technique for ambiguous tasks is:","options":["Writing the longest possible prompt","Using examples of existing patterns from the codebase","Asking the AI to explain its plan first","Describing the task in multiple languages"],"answer":1},{"q":"The fastest vibecoders succeed because they have:","options":["Perfect prompts","Tight feedback loops — direction, evaluate, redirect","The most expensive AI subscription","Memorised all framework APIs"],"answer":1}]}'
),
(
  'les-vc-005', 'crs-vibe-001',
  'Debugging with AI',
  'Turn errors and broken behavior into tight prompts that get fast, accurate fixes.',
  'Debugging is where many new vibecoders get stuck — code breaks and they do not know how to proceed. The key insight is that AI is an exceptional debugging partner when you give it the full error context. When you encounter an error, copy the complete error message including the stack trace, paste it into Composer, and add the relevant code context. Do not say "it does not work" — say: "I get this error when clicking Save: [full error and stack trace]. Here is the handler function: [code]. The expected behavior is [description]." The AI needs exactly the same information a senior engineer would need.

For logic bugs where there is no error thrown but the behavior is wrong, describe the expected versus actual behavior with specific examples. Include the inputs you tested with, the output you got, and the output you expected. After the AI suggests a fix, ask it to explain WHY the fix works — this builds your own understanding and catches cases where the AI fix might introduce a different bug. Review every suggested fix before applying it. AI makes mistakes, especially in edge cases.',
  5, 10,
  '{"questions":[{"q":"When reporting a runtime error to AI for debugging, you should include:","options":["Just the file name","The complete error message, stack trace, and relevant code","Your best guess at the cause","Only the line number where it crashed"],"answer":1},{"q":"For logic bugs with no thrown error, what is most important to describe?","options":["The file size","Whether the code was AI-generated","Expected vs actual behavior with specific inputs and outputs","When the code was last modified"],"answer":2},{"q":"Why should you ask AI to explain a debugging fix?","options":["AI explanations are always required by the license","To make the conversation longer","To build your own understanding and catch potential secondary bugs","It improves AI performance"],"answer":2},{"q":"AI is most effective at debugging when:","options":["Given the minimum possible information","Given full error context, relevant code, and expected behavior","Allowed to rewrite the entire file","Working without constraints"],"answer":1}]}'
);

-- ── LESSONS: AI-Powered Full Stack ────────────────────────────────────────────

INSERT OR IGNORE INTO lessons (id, course_id, title, description, content, position, duration_minutes, quiz) VALUES
(
  'les-vc-006', 'crs-vibe-002',
  'Architecting Before Prompting',
  'Why 20 minutes of architecture planning pays off in dramatically better AI output.',
  'Before generating implementation code, invest time in architecture. A clear architecture brief given to AI produces far better code than ad-hoc requests because each prompt has established context and the AI generates consistent, coherent code. A solid brief covers: the database schema (tables, relationships, indexes), the API surface (server functions or endpoints, their input and output shapes), the component hierarchy (major pages and shared components), and the data flow (how data moves from database to UI). You do not need exhaustive detail — bullet points and TypeScript interfaces work perfectly.

Use AI to help design the architecture before writing any implementation. Describe your product idea and ask: "Design a normalized SQLite schema and a set of server functions for this app. Show me the TypeScript types for the API responses." Evaluate the result critically: is the schema normalized? Are there missing indexes on foreign keys? Does the API design match how the UI will actually query the data? Push back and iterate on the design. A well-designed architecture makes every subsequent prompt faster and the output more reliable because the patterns are established upfront.',
  1, 12,
  '{"questions":[{"q":"When is the best time to invest in architecture when vibecoding?","options":["After the first version ships","Before writing any implementation code","Only if the team has more than 3 people","Architecture is always optional"],"answer":1},{"q":"A solid architecture brief covers:","options":["Line counts and file sizes","Marketing copy and branding","Database schema, API surface, component hierarchy, and data flow","Only the deployment configuration"],"answer":2},{"q":"Using AI to help design architecture before building means:","options":["You never need to review the design","Each implementation prompt has clear context and patterns are established","AI will write perfect code without further guidance","Architecture can be skipped entirely"],"answer":1},{"q":"The most important check when reviewing an AI-generated schema is:","options":["Whether it uses the newest SQL syntax","Whether it is normalized and has proper indexes on foreign keys","How many tables it created","Whether the table names are short"],"answer":1}]}'
),
(
  'les-vc-007', 'crs-vibe-002',
  'Building REST APIs with AI',
  'Generate type-safe, validated API handlers — and know exactly what to review.',
  'REST APIs translate exceptionally well to vibecoding because the structure is predictable: resources, CRUD operations, authentication middleware, and error responses. Start by writing TypeScript interfaces for your resource shapes — the AI will treat these as ground truth. Then describe the operations you need: "Using Hono on Cloudflare Workers, build CRUD endpoints for the Course type. Require session cookie auth. Return 401 if unauthenticated. Validate all inputs with Zod." This single prompt should produce working, type-safe route handlers.

Review every AI-generated API for three things: input validation (is every user-supplied value validated before use?), error handling (are all error paths caught and returning appropriate status codes?), and authentication (is the auth check present on every protected route?). AI-generated APIs frequently have incomplete validation or missing auth on edge-case routes. These gaps are not hard to fix but you must actively look for them. Test each endpoint with a REST client like Bruno as you build — catching a missing auth check in development takes 30 seconds; catching it in production can take hours.',
  2, 14,
  '{"questions":[{"q":"What should you define before asking AI to build an API?","options":["The frontend components","The deployment scripts","TypeScript interfaces for your resource shapes","All the error messages"],"answer":2},{"q":"The three things to review in every AI-generated API are:","options":["Line count, file size, variable names","Input validation, error handling, and authentication","Comments, formatting, naming conventions","Package versions, license, bundle size"],"answer":1},{"q":"AI-generated APIs most frequently have issues with:","options":["Database connection pooling","Incomplete input validation and missing auth on edge-case routes","CSS styling","Bundle optimization"],"answer":1},{"q":"The best time to catch a missing authentication check is:","options":["After users report it in production","Never — AI always gets auth right","During development by testing each endpoint with a REST client","During code review six months later"],"answer":2}]}'
),
(
  'les-vc-008', 'crs-vibe-002',
  'React Frontend Generation',
  'Prompt for components that are typed, responsive, and connected to your data layer.',
  'AI excels at generating React components when you are specific about the data shape, the visual behavior, and the interactions. Structure your frontend prompts by component rather than by page — ask for one well-defined component at a time with a clear props interface. "Build a CourseCard component that receives a Course object (id, title, slug, thumbnail_url, level, description). Render a card with thumbnail, level badge, title, and a hover-to-reveal View Course button. Use Tailwind CSS with a dark background, violet primary color, rounded-2xl corners." This level of specificity produces components you can actually use.

After generation, verify: are the TypeScript types correct and exhaustive? Does the component handle null or undefined props gracefully? Is the layout responsive? AI often generates desktop-only layouts — ask explicitly for mobile improvements: "Make this component responsive — on screens below 640px, stack the layout vertically and make the button full width." For data fetching, describe the React Query pattern: "Add a useQuery hook fetching from getCourses(). Show a skeleton grid while loading. Show an error message on failure." React Query integration is reliable from AI because the pattern is well-documented and consistent.',
  3, 13,
  '{"questions":[{"q":"For best results when prompting for React components, you should:","options":["Ask for the entire page at once","Ask for one component at a time with clear props interface and visual details","Describe only the colors to use","Let the AI decide the component structure"],"answer":1},{"q":"After AI generates a React component, you should verify:","options":["Only that it runs without errors","Type correctness, null handling, and mobile responsiveness","That it has comments on every function","That it uses class components"],"answer":1},{"q":"AI often generates layouts that are:","options":["Mobile-first and fully responsive","Desktop-only — you need to ask for mobile responsiveness explicitly","Too small for desktop screens","Optimized for tablets only"],"answer":1},{"q":"React Query integration with AI-generated code is reliable because:","options":["React Query is built into React","React Query has no edge cases","Its consistent patterns are well-documented in AI training data","AI writes better async code than sync code"],"answer":2}]}'
),
(
  'les-vc-009', 'crs-vibe-002',
  'Database Design via Prompts',
  'Get AI to design normalized schemas and write migrations — then review them like a pro.',
  'Database schema design is one of the highest-leverage uses of vibecoding. A good schema is the foundation of the entire application — get it right and every subsequent layer becomes easier. Start with your product description and ask AI to design a schema: "I am building a learning platform. Users enroll in courses. Courses have ordered lessons with video URLs and text content. Track which lessons each user has completed. Users take a final exam per category and earn a certificate on passing. Design a normalized SQLite schema with appropriate indexes and foreign key constraints." The AI will generate a reasonable starting point.

Evaluate the generated schema critically: is data duplicated unnecessarily (normalization failure)? Are foreign key columns indexed for join performance? Are required columns marked NOT NULL? Are unique constraints present where needed? SQLite has specific behaviors to watch for — booleans stored as INTEGER (0 or 1), JSON stored as TEXT, no native UUID type. Make sure the AI is aware you are using SQLite and D1. For migrations, describe the change precisely: "Add a quiz_results table that links users to lessons, stores their score as INTEGER and passed as INTEGER (0 or 1), with a UNIQUE constraint on (user_id, lesson_id)." Always review AI-generated migrations before applying them to production data.',
  4, 13,
  '{"questions":[{"q":"Why is getting the database schema right especially important in vibecoding?","options":["Schemas are impossible to change later","The schema is the foundation — every layer above depends on it being correct","Databases are the most expensive part of hosting","AI cannot help with schema changes after creation"],"answer":1},{"q":"What should you check in an AI-generated SQLite schema?","options":["Only the table names","Normalization, indexes on foreign keys, NOT NULL constraints, and unique constraints","Whether it uses stored procedures","The number of tables created"],"answer":1},{"q":"A key SQLite behavior to watch for in AI-generated schemas is:","options":["SQLite does not support foreign keys","SQLite uses BOOLEAN as a native type","Booleans are stored as INTEGER (0 or 1), not as BOOLEAN","SQLite automatically indexes all columns"],"answer":2},{"q":"For generating database migrations, you should:","options":["Let the AI decide what to change","Describe the exact change needed with all relevant constraints","Provide your production database credentials","Always use INSERT instead of ALTER TABLE"],"answer":1}]}'
),
(
  'les-vc-010', 'crs-vibe-002',
  'Deploy and Ship',
  'Get your vibecoded app from laptop to production on Cloudflare Workers in under 30 minutes.',
  'Deployment is the final step in the vibecoding loop. Modern platforms like Cloudflare Workers make this straightforward, but there are configuration details to get right. For Cloudflare Workers deployments, the critical file is wrangler.jsonc — it declares your project name, main entry point, compatibility date, and all bindings (D1 databases, KV namespaces, R2 buckets, environment variables). Ask AI to generate your wrangler.jsonc: "Generate a wrangler.jsonc for a TanStack Start SSR app on Cloudflare Workers. It uses a D1 database named DB, needs nodejs_compat compatibility flags, and has a SESSION_SECRET environment variable." Review every binding — incorrect bindings are a common source of production failures.

Environment variables and secrets require special handling. Never commit API keys or secrets to source control. Use `wrangler secret put SECRET_NAME` to set production secrets, and a .dev.vars file for local development (add it to .gitignore). AI-generated code often includes placeholder secrets — find and replace them before deploying. Build a deployment checklist: run `npm run build` and fix TypeScript errors, review wrangler.jsonc bindings, confirm all secrets are set in production with `wrangler secret list`, deploy with `wrangler deploy`, then run a smoke test on the live URL.',
  5, 12,
  '{"questions":[{"q":"The critical configuration file for a Cloudflare Workers deployment is:","options":["package.json","vite.config.ts","wrangler.jsonc","tsconfig.json"],"answer":2},{"q":"How should production API keys and secrets be handled?","options":["Hardcoded in source code for simplicity","In a .env file committed to git","Set with wrangler secret put and kept out of source control","Stored in the database"],"answer":1},{"q":"A deployment checklist should include:","options":["Only running npm run build","Build, TypeScript error check, config review, secrets verification, and smoke test","Just checking that the URL loads","Only reviewing the database migrations"],"answer":1},{"q":"Where should local development environment variables be stored?","options":[".env committed to git","In wrangler.jsonc directly","In a .dev.vars file added to .gitignore","In the source code as constants"],"answer":1}]}'
);

-- ── LESSONS: React & TypeScript Essentials ────────────────────────────────────

INSERT OR IGNORE INTO lessons (id, course_id, title, description, content, position, duration_minutes, quiz) VALUES
(
  'les-fe-001', 'crs-fe-001',
  'React 19 Fundamentals',
  'The most impactful changes in React 19: the compiler, server components, and Suspense.',
  'React 19 is the most significant React release in years, introducing a compiler that handles automatic memoization, stable React Server Components, and improved Suspense integration. The React Compiler (previously called React Forget) analyzes your components at build time and automatically inserts useMemo and useCallback where needed — eliminating most manual performance optimization boilerplate. Write normal, readable components and the compiler makes them fast.

React Server Components (RSC) are now stable. RSCs run exclusively on the server, contribute zero JavaScript to the client bundle, and can access databases and secrets directly. Use Server Components for data-display layers: product listings, article content, user profiles. Use Client Components (marked with "use client" at the top of the file) only where browser interactivity or browser APIs are required. This server/client boundary is the central design decision in modern React architecture. Suspense makes async loading states declarative: wrap any component that might be waiting for data in a Suspense boundary with a fallback: <Suspense fallback={<Skeleton />}><DataComponent /></Suspense>.',
  1, 12,
  '{"questions":[{"q":"What does the React Compiler (React Forget) do?","options":["Compiles JSX to HTML","Automatically handles memoization, eliminating most useMemo and useCallback boilerplate","Converts TypeScript to JavaScript","Bundles your application for production"],"answer":1},{"q":"When should you use a React Server Component?","options":["Whenever interactivity is needed","For all components regardless of use case","For data-display components that do not need browser APIs or interactivity","Only for authentication flows"],"answer":2},{"q":"A Client Component is created by:","options":["Adding a type annotation","Using class syntax","Adding use client at the top of the file","Importing from react-dom/client"],"answer":2},{"q":"Suspense boundaries are used to:","options":["Handle routing transitions","Style loading indicators with CSS","Declare async loading states declaratively — show a fallback while waiting for data","Validate form inputs before submission"],"answer":2}]}'
),
(
  'les-fe-002', 'crs-fe-002',
  'TypeScript for React',
  'Type your props, use generics where they earn their complexity, and let inference do the rest.',
  'TypeScript eliminates entire categories of runtime bugs that would otherwise reach users: undefined is not a function, property X does not exist on type Y, expected string received number. For any project of meaningful complexity, TypeScript is not optional — it is the best documentation you have. The most common pattern is typing component props: define an interface for every component and pass it as the generic argument. interface ButtonProps { label: string; onClick: () => void; variant?: "primary" | "outline" }. Using union types for constrained values and ? for optional props makes misuse impossible to compile.

Generic types unlock reusable, type-safe utilities without repetition. A useLocalStorage<T>(key: string, initial: T) hook that works correctly for any serializable type is more valuable than separate hooks for each data type. Add generics only when the same logic repeats across multiple types — premature generics add complexity without value. For most code, lean on type inference: TypeScript can infer return types of functions, types of local variables, and types flowing through map/filter/reduce chains. Annotate function parameters, component props, and server function signatures. Let inference handle the rest.',
  1, 11,
  '{"questions":[{"q":"The primary benefit of TypeScript in React projects is:","options":["Faster build times","Catching type errors at compile time rather than in production at runtime","Smaller JavaScript bundle sizes","Automatic code formatting"],"answer":1},{"q":"For a ButtonProps interface, using variant?: primary | outline means:","options":["The variant prop is required","Variant can be any string value","Variant is optional and must be one of exactly two values","Variant defaults to primary"],"answer":2},{"q":"Generic types are most valuable when:","options":["For every single function you write","When a function or hook should work correctly with multiple different types","Only in third-party library code","When you want to slow down the TypeScript compiler"],"answer":1},{"q":"TypeScript type inference means you can:","options":["Skip TypeScript entirely","Skip annotations where TypeScript can determine the type from context","Only get type safety on primitive values","Annotate nothing at all"],"answer":1}]}'
),
(
  'les-fe-003', 'crs-fe-003',
  'Hooks Deep Dive',
  'useState, useEffect, useRef, and useReducer — the subtle rules that prevent bugs.',
  'React hooks replaced class components and gave functional components access to state and lifecycle. Mastering the core hooks means understanding their subtle rules, not just their syntax. For useState, the critical rule is that state updates are asynchronous and batched — you cannot read the updated value in the same call that set it. When new state depends on previous state, always use the updater function form: setCount(prev => prev + 1) instead of setCount(count + 1). The updater form is always safe in concurrent mode and async contexts; the direct form can silently produce wrong results with stale closures.

useEffect runs after paint, not during rendering. The dependency array controls when it re-runs: no array means every render, empty array means once on mount, values in the array mean re-run when those values change. The cleanup function returned from useEffect is critical — it runs before the next effect execution and on unmount. Use it to cancel timeouts, unsubscribe from events, and abort fetch requests. Missing cleanup causes memory leaks and bugs that are hard to reproduce. useReducer is the right tool when state has multiple related fields that change together — define an explicit action type union and a pure reducer function. This makes every state transition visible, testable, and impossible to partially apply.',
  1, 14,
  '{"questions":[{"q":"When new state depends on the previous state, you should use:","options":["The direct form: setState(count + 1)","The updater form: setState(prev => prev + 1)","useEffect to read the latest value","useRef to track the previous value"],"answer":1},{"q":"An empty dependency array [] in useEffect means:","options":["The effect never runs","The effect runs after every render","The effect runs once after the component mounts","The effect runs synchronously during render"],"answer":2},{"q":"The cleanup function in useEffect should:","options":["Set state to its initial value","Cancel subscriptions, timeouts, and fetch requests to prevent memory leaks","Log a message when the component unmounts","Return the new state value"],"answer":1},{"q":"useReducer is preferred over useState when:","options":["You have a single boolean value","State has multiple related fields that change together with explicit action types","You need to fetch data from an API","Rendering a completely static component"],"answer":1}]}'
),
(
  'les-fe-004', 'crs-fe-004',
  'State Management Patterns',
  'Match the right state tool to each problem: local, context, Zustand, or React Query.',
  'State management exists on a spectrum and the mistake most developers make is picking one tool for everything. Local useState handles isolated, component-specific UI state: a dialog open/closed, a form input value, a toggle. Context API handles global state that changes infrequently: the current user, the color theme, the locale. Zustand handles shared application state that changes frequently. React Query handles all server state. Each tool exists because the others are wrong for that specific job.

The Context API limitation that matters most is performance: every context update rerenders ALL consumers of that context, regardless of whether they use the specific value that changed. For values that change infrequently like the current user or theme, this is fine. For values that change on every keystroke or scroll event, Context causes cascading rerenders across your entire component tree. Zustand solves this with selective subscriptions — a component subscribes to only the store values it reads, so it only rerenders when those specific values change. For forms, React Hook Form tracks form state in a ref (not useState), meaning the component does not rerender on every keystroke — only on submit or explicit validation triggers.',
  1, 13,
  '{"questions":[{"q":"Which state tool should you use for data fetched from a server API?","options":["useState for all fetched data","Context API for shared data","React Query — it is designed specifically for server state","Zustand for everything"],"answer":2},{"q":"The main performance problem with Context API is:","options":["Context is slow to initialize","Every context update rerenders all consumers, even those that do not use the changed value","Context only works in class components","Context cannot store arrays or objects"],"answer":1},{"q":"Zustand is more performant than Context for frequently changing state because:","options":["Zustand uses WebWorkers","Components subscribe to only the specific store values they read","Zustand automatically batches all updates","Zustand stores data outside the React tree entirely"],"answer":1},{"q":"React Hook Form tracks form state in a ref rather than useState, which means:","options":["Form values are not reactive","The component rerenders on every keystroke","The component only rerenders on submit or validation — not on every keystroke","Form state cannot be read outside the form"],"answer":2}]}'
),
(
  'les-fe-005', 'crs-fe-005',
  'React Query & Server State',
  'useQuery, useMutation, cache invalidation, and optimistic updates — the complete pattern.',
  'React Query (TanStack Query) solves server state management: fetching data, handling loading and error states, caching results, keeping data fresh, and deduplicating requests. The useQuery hook takes a queryKey array (the cache key) and a queryFn (a function that returns a promise). Include every variable your query depends on in the queryKey — if you fetch a course by ID, the key is ["course", courseId]. React Query will automatically refetch when the key changes, cache the result while it is fresh, and provide isLoading, isError, and data flags for your rendering logic.

useMutation handles write operations: creating, updating, deleting. Define onSuccess and onError callbacks to handle the result. The most important pattern after a successful mutation is cache invalidation: call queryClient.invalidateQueries({ queryKey: ["courses"] }) to mark the cached data as stale and trigger a background refetch. Without invalidation, users see stale data after they make a change. Optimistic updates go further — update the cache immediately when the user acts (before the server responds), then roll back if the request fails. Use onMutate to apply the optimistic update, onError to roll back, and onSettled to invalidate and refetch. This technique makes writes feel instant.',
  1, 14,
  '{"questions":[{"q":"The queryKey in useQuery serves as:","options":["The API endpoint URL to fetch from","The cache key — include every variable the query depends on","A display label shown in the React DevTools","The TypeScript type of the response data"],"answer":1},{"q":"After a successful mutation, you typically call:","options":["window.location.reload() to see fresh data","queryClient.invalidateQueries() to mark stale data and trigger a refetch","localStorage.clear() to reset the cache","router.refresh() to hard-reload the page"],"answer":1},{"q":"Optimistic updates mean:","options":["Only fetching data when the network is fast","Pre-caching data the user might need","Updating the UI immediately before server confirmation, then rolling back on failure","Caching all queries permanently and never refetching"],"answer":2},{"q":"What causes users to see stale data after a mutation?","options":["React Query caches too aggressively","Forgetting to call queryClient.invalidateQueries after a successful mutation","Using useMutation instead of useQuery","Setting staleTime to 0"],"answer":1}]}'
);

-- ── LESSONS: Tailwind CSS Mastery ─────────────────────────────────────────────

INSERT OR IGNORE INTO lessons (id, course_id, title, description, content, position, duration_minutes, quiz) VALUES
(
  'les-fe-006', 'crs-fe-002',
  'Tailwind Core Concepts',
  'Utility-first CSS: why it works, how the class system is organized, and how to configure it.',
  'Tailwind CSS is a utility-first CSS framework where you compose utility classes that describe what an element looks like rather than writing custom class names that describe what it is. Every utility maps directly to one or a small set of CSS properties — no magic, no hidden abstractions. flex sets display: flex. items-center sets align-items: center. rounded-2xl sets border-radius: 1rem. The complete Tailwind class system is organized by CSS property category: layout (flex, grid), spacing (p-4, m-8, gap-3), sizing (w-full, h-12), typography (text-sm, font-bold), backgrounds (bg-primary, bg-card), borders (border, rounded-2xl), effects (shadow, opacity), and transitions (transition, duration-150). Learn these groups and you can build any UI.

The tailwind.config.ts file extends Tailwind with your design system. Define custom colors as CSS variable references: "primary": "hsl(var(--primary))" — this allows bg-primary to resolve to different values in light and dark mode because the CSS variable changes. Define custom font families, spacing scales, and keyframe animations here. The JIT (Just-In-Time) compiler generates only the CSS classes your project actually uses, so the production bundle is typically under 15kb regardless of Tailwind version size. You can also use arbitrary values in square brackets for one-off values: w-[340px], bg-[#ff6b6b], grid-cols-[1fr_2fr].',
  1, 12,
  '{"questions":[{"q":"Tailwind CSS is utility-first, meaning:","options":["It is optimized for loading performance","Classes describe how elements look, not semantic names for what they are","It has the most utility functions of any CSS framework","It loads all utilities from a CDN"],"answer":1},{"q":"To define a custom color that works with Tailwind opacity modifiers (bg-primary/80), you should:","options":["Use a hex value directly","Use rgb() notation","Use hsl() notation with the hsl() wrapper","Use hsl values without the hsl() wrapper, as a CSS variable reference"],"answer":3},{"q":"The Tailwind JIT compiler:","options":["Runs your TypeScript at build time","Generates only the CSS classes your project actually uses, keeping bundles small","Compiles JSX to HTML","Minifies all JavaScript in the project"],"answer":1},{"q":"Arbitrary values in Tailwind (like w-[340px]) are used for:","options":["Overriding browser defaults","One-off values that do not belong in the config but are needed for a specific case","Replacing CSS variables","Disabling the JIT compiler"],"answer":1}]}'
),
(
  'les-fe-007', 'crs-fe-002',
  'Responsive Layouts',
  'Mobile-first breakpoints, Flexbox, and CSS Grid — everything you need for any layout.',
  'Tailwind uses five responsive breakpoints: sm (640px), md (768px), lg (1024px), xl (1280px), and 2xl (1536px). Apply them as prefixes to any utility: hidden md:block, grid-cols-1 sm:grid-cols-2 lg:grid-cols-3. Tailwind is mobile-first — the unprefixed class applies at all screen sizes, and prefixed classes apply at that breakpoint and above. This means you design for mobile first, then add classes to adjust the layout at larger sizes, which typically requires fewer overrides and produces cleaner code.

Flexbox is the workhorse for one-dimensional layouts: rows or columns of items. Use flex for the container, items-center and justify-between for alignment, gap-4 for spacing, and flex-1 on a child to fill remaining space. CSS Grid handles two-dimensional layouts: grids of rows and columns. grid grid-cols-3 gap-6 creates a three-column grid. col-span-2 spans two columns. lg:grid-cols-[320px_1fr] creates a fixed-width sidebar with a flexible main area. For card grids that automatically fit as many items as will fill the space, use grid-cols-[repeat(auto-fill,minmax(280px,1fr))]. The container utility with max-w-7xl mx-auto px-4 sm:px-6 is the standard page wrapper: centered, max-width capped, with responsive horizontal padding.',
  2, 12,
  '{"questions":[{"q":"Tailwind responsive prefixes use a mobile-first approach, which means:","options":["Styles only apply on mobile devices","The unprefixed class applies at all sizes; prefixed classes apply at that breakpoint and above","Desktop is designed first and mobile overrides are applied","Breakpoints are applied in descending order"],"answer":1},{"q":"For a card grid that shows 1 column on mobile and 3 on large screens:","options":["Use float: left on each card","Use grid grid-cols-1 lg:grid-cols-3","Use flex with fixed widths on children","Use position: absolute on each card"],"answer":1},{"q":"The CSS Grid utility col-span-2 means:","options":["The element is in grid column 2","The grid has 2 columns total","The element spans across 2 column tracks","The element has 2 child items"],"answer":2},{"q":"The standard Tailwind page wrapper pattern is:","options":["container mx-auto","w-full max-w-screen","max-w-7xl mx-auto px-4 sm:px-6","div with width: 100%"],"answer":2}]}'
),
(
  'les-fe-008', 'crs-fe-002',
  'Dark Mode & Theming',
  'CSS variables, the dark: modifier, and a design token system that works across both modes.',
  'Dark mode in modern web apps is implemented with CSS custom properties that resolve to different values based on a .dark class on the HTML root element. In tailwind.config.ts, set darkMode: "class". Then in your global CSS, define your color variables under :root for light mode and .dark for dark mode: :root { --background: 0 0% 100%; } .dark { --background: 222 84% 5%; }. Using HSL values WITHOUT the hsl() wrapper is important — it allows Tailwind opacity modifiers to work: bg-background/80 produces a semi-transparent background. With the hsl() wrapper, opacity modifiers would fail.

A design token system replaces hardcoded colors with semantic names. Instead of text-gray-900 dark:text-white (two classes, duplicated everywhere), use text-foreground (one class, correct in both modes). Standard semantic tokens: background (page surface), foreground (primary text), card (card and panel backgrounds), primary (brand/action color), muted (de-emphasized backgrounds and text), border (dividers and outlines), destructive (errors and warnings). Toggle dark mode by adding or removing the dark class on document.documentElement. Persist preference in localStorage and detect system preference with window.matchMedia("(prefers-color-scheme: dark)") for first-load behavior.',
  3, 11,
  '{"questions":[{"q":"How should dark mode be implemented in Tailwind for class-based toggling?","options":["Using @media (prefers-color-scheme) only","CSS variables under :root and .dark, with darkMode: class in config","Duplicate all utility classes with a dark- prefix","A separate stylesheet for dark mode"],"answer":1},{"q":"Why define HSL colors WITHOUT the hsl() wrapper in CSS variables?","options":["hsl() notation is not supported in CSS variables","It allows Tailwind opacity modifiers like bg-primary/80 to work correctly","It is faster than using hsl()","CSS variables cannot contain function calls"],"answer":1},{"q":"A design token system with semantic names (background, foreground, primary) means:","options":["You always use hardcoded hex values","You need a separate class for each theme","One class like text-foreground works correctly in both light and dark mode","Only dark mode is supported"],"answer":2},{"q":"To toggle dark mode in JavaScript:","options":["Set document.body.style.backgroundColor","Add or remove the dark class on document.documentElement","Call window.darkMode.toggle()","Use React state to pass a theme prop everywhere"],"answer":1}]}'
),
(
  'les-fe-009', 'crs-fe-002',
  'Component Patterns & CVA',
  'Type-safe variant management with CVA, compound components with Radix, and the cn() utility.',
  'Production component systems need variant management — a Button that can be primary, outline, destructive, ghost, and each variant with a different size. Writing a separate component for each combination is unmaintainable. Class Variance Authority (CVA) is the standard solution. Call cva() with base classes (always applied) and a variants object (classes applied when a variant value matches). The result is a function that takes variant selections and returns the merged class string: const button = cva("rounded-lg font-medium transition-colors", { variants: { variant: { primary: "bg-primary text-white", outline: "border border-primary text-primary" }, size: { sm: "h-8 px-3 text-sm", md: "h-10 px-4" } } }). TypeScript automatically types the variant arguments.

The cn() utility is essential for any component that accepts a className prop. It merges Tailwind classes intelligently using tailwind-merge and clsx: cn("bg-primary hover:bg-primary/90", className). tailwind-merge resolves conflicts so a consumer passing className="bg-destructive" correctly overrides the default bg-primary rather than both classes being present. Compound components (like Radix UI Tabs with TabsList, TabsTrigger, TabsContent) share state through React Context rather than prop drilling. Add Tailwind classes to Radix headless components to build a complete, accessible component system with minimal custom logic.',
  4, 13,
  '{"questions":[{"q":"What problem does CVA (Class Variance Authority) solve?","options":["CSS loading performance","Type-safe, maintainable management of component visual variants","Server-side rendering of styles","State management for interactive components"],"answer":1},{"q":"The cn() utility uses tailwind-merge to:","options":["Bundle all CSS into a single file","Intelligently merge Tailwind classes and resolve conflicts (e.g. two bg- classes)","Validate that class names exist in Tailwind","Generate TypeScript types for class names"],"answer":1},{"q":"Compound components (like Radix Tabs) share state through:","options":["URL query parameters","Prop drilling from parent to all children","React Context between the related sub-components","A global Zustand store"],"answer":2},{"q":"When a consumer passes className to a component that already has a matching Tailwind class:","options":["Both classes are applied and the first one wins","The consumer class is ignored","tailwind-merge resolves the conflict, keeping only the consumer class","CSS specificity resolves it randomly"],"answer":1}]}'
),
(
  'les-fe-010', 'crs-fe-002',
  'Animations & Micro-interactions',
  'Tailwind transitions for basic polish, keyframes for entrances, and when to reach for framer-motion.',
  'Micro-interactions are the small animations that make a UI feel alive: a button that gives subtle press feedback, a modal that slides in smoothly, a success state that bounces with delight. Tailwind provides transition utilities for smooth property changes: transition (shorthand for all), transition-colors (only colors), duration-150 (150ms), ease-out (timing function). Combine with hover: and active: variants for tactile feedback: hover:scale-105 active:scale-95 transition-transform duration-150. This three-utility pattern gives buttons physical press feedback with zero JavaScript. Apply transition-colors duration-200 to interactive elements like links and cards to make the entire interface feel responsive.

For entrance animations, define custom keyframes in tailwind.config.ts: keyframes: { "slide-up": { from: { opacity: "0", transform: "translateY(16px)" }, to: { opacity: "1", transform: "translateY(0)" } } }. Add it to the animation config: animation: { "slide-up": "slide-up 0.3s ease-out" }. Apply animate-slide-up to components entering the DOM. For complex sequences — multi-step animations, physics spring curves, shared element transitions between routes — add framer-motion. motion.div adds declarative animation props: initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}. The layout prop enables automatic FLIP animations when elements change size or position. Use framer-motion selectively for high-value interactions — most UI polish is achievable with Tailwind transitions.',
  5, 12,
  '{"questions":[{"q":"To give a button a tactile press effect in Tailwind, you use:","options":["A JavaScript click handler that modifies style","hover:scale-105 active:scale-95 transition-transform duration-150","A CSS animation class applied on click","box-shadow changes only"],"answer":1},{"q":"Custom entrance animation keyframes in Tailwind are defined in:","options":["A separate animations.css file","The component file with inline styles","The keyframes section of tailwind.config.ts","A CSS-in-JS library"],"answer":2},{"q":"You should reach for framer-motion instead of Tailwind transitions when:","options":["For all animations in your project","For basic hover effects on buttons","For complex sequences, physics springs, or shared element transitions","Only for loading spinners"],"answer":2},{"q":"The transition-colors duration-200 class combination is commonly applied to:","options":["Page backgrounds only","Interactive elements like links and cards to make color changes feel smooth","Images and media","Non-interactive static text"],"answer":1}]}'
);

-- ── MODULE EXAMS ──────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO module_exams (id, category_id, title, questions, pass_score) VALUES
(
  'ex-vibe-001',
  'cat-vibecoding',
  'Vibecoding Mastery Exam',
  '[{"q":"Who coined the term Vibecoding?","options":["Sam Altman","Andrej Karpathy","Linus Torvalds","Jeff Dean"],"answer":1},{"q":"What is the core vibecoding loop?","options":["design-code-test-deploy","describe-generate-review-ship","plan-build-monitor-iterate","sketch-prototype-test-launch"],"answer":1},{"q":"Vibecoding is best described as:","options":["Letting AI write all code without any review","Pure code generation without understanding","Pair programming with AI where you steer and review the output","Having AI run your entire team"],"answer":2},{"q":"The most important skill for a vibecoder is:","options":["Memorising syntax","Speed-typing","Understanding code well enough to evaluate and steer AI output","Knowing every framework API"],"answer":2},{"q":"The .cursorrules file configures:","options":["Keyboard shortcuts","Linting and formatting rules","AI conventions about your stack and coding style","Production deployment settings"],"answer":2},{"q":"Cursor Composer mode is opened with:","options":["Cmd+P / Ctrl+P","Cmd+K / Ctrl+K","Cmd+I / Ctrl+I","Cmd+Shift+P / Ctrl+Shift+P"],"answer":2},{"q":"When writing a vibecoding prompt, you should describe:","options":["Individual functions to write","Line-by-line implementation instructions","The full product with stack, data shapes, features, and visual direction","Only the database schema"],"answer":2},{"q":"Vague prompts produce:","options":["Better code because the AI has creative freedom","Vague code that needs more iteration","Syntax errors","Faster results"],"answer":1},{"q":"The most effective technique for ambiguous coding tasks is:","options":["Writing the longest possible prompt","Providing examples of existing patterns from the codebase","Describing the task in multiple languages","Asking the AI to explain its plan before coding"],"answer":1},{"q":"When asking AI to debug a runtime error, you should include:","options":["Just the error message","The complete error, stack trace, and relevant code context","Only your best guess at the cause","Only the line number"],"answer":1},{"q":"For logic bugs with no thrown error, what is most critical to describe?","options":["The file size and line count","When the code was last modified","Expected vs actual behavior with specific inputs and outputs","The AI model that generated the code"],"answer":2},{"q":"Before generating implementation code, you should invest time in:","options":["Writing documentation","Architecture: schema, API surface, component hierarchy, and data flow","Marketing copy","CI/CD configuration"],"answer":1},{"q":"A well-designed architecture makes vibecoding faster because:","options":["It reduces the number of AI tokens consumed","Each prompt has clear context and patterns are established upfront","AI writes fewer lines of code","Architecture eliminates the need for testing"],"answer":1},{"q":"What should you define FIRST before asking AI to build an API?","options":["The frontend components","The deployment scripts","TypeScript interfaces for your resource shapes","All the error message strings"],"answer":2},{"q":"AI-generated APIs most often have issues with:","options":["Naming conventions","Incomplete input validation and missing auth on edge-case routes","CSS styling","Bundle size optimization"],"answer":1},{"q":"For prompting React component generation, what produces the best results?","options":["Asking for an entire page at once","One component at a time with a clear TypeScript props interface and visual description","Only describing the colors to use","Letting the AI decide the component structure"],"answer":1},{"q":"AI often generates React layouts that are:","options":["Mobile-first and fully responsive by default","Too minimal","Desktop-only — you must ask for mobile responsiveness explicitly","Optimized for tablets only"],"answer":2},{"q":"A good database schema is important because:","options":["Schemas are impossible to change later","It is the foundation — every layer of the app depends on it being correct","Databases are the most expensive hosting cost","AI cannot help with schema changes"],"answer":1},{"q":"In SQLite, booleans are stored as:","options":["BOOLEAN native type","TRUE/FALSE keywords","INTEGER (0 or 1)","BIT type"],"answer":2},{"q":"The critical Cloudflare Workers deployment config file is:","options":["package.json","vite.config.ts","wrangler.jsonc","tsconfig.json"],"answer":2},{"q":"Production secrets should be set using:","options":["Hardcoded constants in source code","A .env file committed to git","wrangler secret put","In the source code as comments"],"answer":2},{"q":"The best time to catch a missing auth check is:","options":["After users report it in production","During development testing with a REST client","At code review six months later","Never — auth checks are always correct"],"answer":1},{"q":"React Query integration works reliably with AI-generated code because:","options":["React Query is built into React itself","Its consistent, well-documented patterns are represented in AI training data","AI writes better async code than sync code","React Query has no edge cases"],"answer":1},{"q":"After a successful mutation, you must call:","options":["window.location.reload()","queryClient.invalidateQueries() to mark stale data and trigger a refetch","localStorage.clear()","router.refresh()"],"answer":1},{"q":"The deployment checklist should include:","options":["Only running npm run build","Build, TypeScript errors, config review, secrets verification, smoke test","Just checking that the URL loads","Only reviewing database migrations"],"answer":1},{"q":"The main goal of your first vibecoding session should be:","options":["Writing perfect production-ready code","Shipping something that works and building momentum","Documenting the entire codebase","Optimizing performance metrics"],"answer":1},{"q":"When iterating on a vibecoded app, each iteration prompt should:","options":["Rewrite the entire codebase from scratch","Address specific problems or improvements observed in the running app","Add as many features as possible","Change the tech stack"],"answer":1},{"q":"The three layers of a well-structured code prompt are:","options":["Title, body, and conclusion","Context, task, and constraints","Frontend, backend, and database","Input, processing, and output"],"answer":1},{"q":"AI is most effective at debugging when given:","options":["The minimum amount of information","Full error context, relevant code, and the expected behavior","Permission to rewrite the entire file","No constraints or requirements"],"answer":1},{"q":"Vibecoding does NOT replace the need for:","options":["A computer","The internet","Programming knowledge and the ability to review and steer AI output","A text editor"],"answer":2}]',
  70
),
(
  'ex-fe-001',
  'cat-frontend',
  'Frontend Development Exam',
  '[{"q":"What does the React Compiler (React Forget) do?","options":["Compiles JSX to HTML","Automatically handles memoization, removing most useMemo and useCallback boilerplate","Converts TypeScript to JavaScript","Bundles your application"],"answer":1},{"q":"React Server Components run:","options":["Only in the browser","Only on the server, contributing zero JS to the client bundle","In both environments simultaneously","In a Web Worker"],"answer":1},{"q":"A Client Component is created by:","options":["Using class syntax","Extending React.Component","Adding use client at the top of the file","Using ReactDOM.render()"],"answer":2},{"q":"Suspense boundaries are used to:","options":["Handle URL routing","Declare async loading states — show a fallback while a child waits for data","Validate form inputs","Style loading spinners with CSS"],"answer":1},{"q":"When typing component props in TypeScript, you should:","options":["Use any for all props","Define an interface and mark optional props with ?","Skip types for simple components","Use PropTypes from prop-types package"],"answer":1},{"q":"Generic types are most valuable when:","options":["For every function you write","A function or hook should work correctly with multiple different types","Only in third-party library code","Never — they are too complex"],"answer":1},{"q":"TypeScript type inference means:","options":["You skip TypeScript entirely","You annotate nothing at all","You can skip annotations where TypeScript can determine the type from context","You only get types on primitive values"],"answer":2},{"q":"The updater form setState(prev => prev + 1) is important because:","options":["It is the only valid syntax","It avoids stale closure bugs in concurrent mode and async contexts","It is faster than the direct form","It is required for hooks to work"],"answer":1},{"q":"An empty dependency array [] in useEffect means:","options":["The effect never runs","The effect runs after every render","The effect runs once after the component mounts","The effect runs synchronously during render"],"answer":2},{"q":"The cleanup function in useEffect:","options":["Resets state to its initial value","Cancels subscriptions and timeouts to prevent memory leaks","Returns the new state value","Runs before the component renders"],"answer":1},{"q":"useReducer is preferred over useState when:","options":["You have a single boolean value","State has multiple related fields that transition together with explicit action types","You need to fetch data from an API","Rendering a static component"],"answer":1},{"q":"Context API should NOT be used for:","options":["The current user session","Application theme preference","Locale and language settings","Values that change on every keystroke or frequently"],"answer":3},{"q":"Zustand is more performant than Context for shared state because:","options":["Zustand uses WebWorkers","Components subscribe to only the specific store values they read","Zustand automatically batches all updates","Zustand stores data outside React entirely"],"answer":1},{"q":"React Hook Form tracks form state in:","options":["useState — one state per input","A ref — avoiding rerenders on each keystroke","A global Zustand store","The URL query string"],"answer":1},{"q":"The queryKey in useQuery is used as:","options":["The API endpoint URL","A display label in DevTools","The cache key — include every variable the query depends on","The TypeScript type of the response"],"answer":2},{"q":"After a successful mutation, you should call:","options":["window.location.reload()","queryClient.invalidateQueries() to mark cached data as stale","localStorage.clear()","A hard page navigation"],"answer":1},{"q":"Optimistic updates mean:","options":["Only fetching data when the network is fast","Pre-caching data users might need in the future","Updating the UI immediately before server confirmation, rolling back on failure","Caching all queries permanently"],"answer":2},{"q":"Tailwind CSS is utility-first, meaning:","options":["It is the fastest CSS framework available","Classes describe how elements look (visual utilities) rather than what they are","It has the most utility functions","It loads utilities from a CDN"],"answer":1},{"q":"CSS variable colors in Tailwind should be defined WITHOUT the hsl() wrapper so:","options":["CSS variables cannot contain function calls","hsl() notation is not supported","Tailwind opacity modifiers like bg-primary/80 work correctly","It loads faster"],"answer":2},{"q":"The Tailwind JIT compiler:","options":["Runs TypeScript at build time","Generates only the CSS classes actually used in the project","Compiles JSX to HTML","Minifies JavaScript"],"answer":1},{"q":"Tailwind responsive prefixes are mobile-first, which means:","options":["Styles only apply on mobile","The unprefixed class applies at all sizes; prefixed classes apply at that breakpoint and above","Desktop is designed first","Breakpoints work in descending order"],"answer":1},{"q":"grid grid-cols-1 lg:grid-cols-3 creates:","options":["A 3-column grid on all screens","A 1-column grid on all screens","A 1-column grid on small screens, 3-column grid on large screens","A 3-column grid that collapses to 1 on large screens"],"answer":2},{"q":"Dark mode in Tailwind is implemented by:","options":["A media query only approach","CSS variables under :root and .dark with darkMode: class in config","Duplicating all classes with dark- prefix","A separate dark-mode stylesheet"],"answer":1},{"q":"HSL colors in CSS variables work WITHOUT hsl() wrapper because:","options":["hsl() is not supported in CSS","It is just a convention with no technical reason","It allows Tailwind opacity modifiers to construct the hsl() call with the alpha parameter","CSS variables automatically add hsl()"],"answer":2},{"q":"CVA (Class Variance Authority) solves:","options":["CSS loading performance","Type-safe, maintainable management of component visual variants","Server-side rendering","State management"],"answer":1},{"q":"The cn() utility combines tailwind-merge and clsx to:","options":["Bundle CSS files together","Merge Tailwind classes and resolve conflicts so consumers can safely override styles","Validate that class names exist","Generate TypeScript types for class names"],"answer":1},{"q":"Compound components share state through:","options":["URL query parameters","Prop drilling from parent to all children","React Context between the related sub-components","A global Zustand store"],"answer":2},{"q":"To give a button tactile press feedback with no JavaScript:","options":["Add an onClick handler that modifies style","Use hover:scale-105 active:scale-95 transition-transform duration-150","Apply a CSS animation on the active pseudo-class","Use box-shadow changes only"],"answer":1},{"q":"Custom keyframe animations in Tailwind are defined in:","options":["A separate animations.css file","Inline styles","The keyframes section of tailwind.config.ts","CSS-in-JS"],"answer":2},{"q":"You should use framer-motion instead of Tailwind transitions when:","options":["For all animations","For basic hover effects","For complex sequences, physics springs, or shared element transitions","Only for loading spinners"],"answer":2}]',
  70
);
